div.listPerson:
{% for x in objects %}

      {{ x.label }}
      {% for y in x.titel %}

         {{ y.value }}

      {% endfor %}
      {% if x.place_of_birth or x.date_of_birth %}
      {% if x.date_of_birth %}
         {{ x.date_of_birth }}{% endif %}
         {% for p in x.place_of_birth %}

            {{ p.label }}{% if p.latitude %}
            {{ p.latitude }} {{ p.longitude }}{% endif %}
            {% if p.geonames_url %}
            {{ p.geonames_url }}
            {% endif %}
         {% endfor %}

      {% endif %}
      {% if x.place_of_death or x.date_of_death %}
      {% if x.date_of_death %}
         {{ x.date_of_death }}{% endif %}
         {% for p in x.place_of_death %}

            {{ p.label }}{% if p.latitude %}
            {{ p.latitude }} {{ p.longitude }}{% endif %}
            {% if p.geonames_url %}
            {{ p.geonames_url }}
            {% endif %}
         {% endfor %}

      {% endif %}
      {% if x.gnd_url|length > 0 %}
      {{ x.gnd_url }}
      {% endif %}
      {% if x.ndb|length > 0 %}
      {{ x.ndb }}
      {% endif %}
      {% if x.wikidata_url|length > 0 %}
      {{ x.wikidata_url }}
      {% endif %}
      {% if x.other_url|length > 0 %}
      {{ x.other_url }}
      {% endif %}
      {% if x.img_source %}


         {{ x.img_name }}

      {% endif %}

{% endfor %}
